import React from 'react';
import './Penguin.css'
const Penguin: React.FunctionComponent = () => {
    return (
        <div className='penguin'>
            <div className='penguin-top'>
                <div className='penguin-left-cheek'></div>
                <div className='penguin-right-cheek'></div>
                <div className='penguin-left-eye'></div>
                <div className='penguin-right-eye'></div>
                <div className='penguin-belly'></div>
                <div className='penguin-right-belly'></div>
            </div>
            <div className='penguin-bottom'>
                <div className='penguin-left-hand'></div>
                <div className='penguin-right-hand'></div>
                <div className='penguin-left-feet'></div>
                <div className='penguin-right-feet'></div>
            </div>
        </div>
    )
};

export default Penguin;
